using SkiaSharp;
using System;
try
{
    byte[] pngBytes = new byte[] { /* 1x1 PNG */ };
    Console.WriteLine("Before SKImage.FromEncodedData...");
    SKImage image = SKImage.FromEncodedData(pngBytes);
    Console.WriteLine($"SUCCESS: Image created: {image.Width}x{image.Height}");
}
catch (TypeInitializationException ex)
{
    Console.Error.WriteLine($"TypeInitializationException: {ex.Message}");
    Console.Error.WriteLine($"Inner: {ex.InnerException?.Message}");
    Environment.Exit(1);
}
